// src/context/StudentProfileContext.jsx
import { createContext, useContext, useState, useEffect } from "react";
import { getStudentProfile } from "../api/auth";

const StudentProfileContext = createContext(null);
const CACHE_KEY = "zenelait-student-profile";

export const StudentProfileProvider = ({ children }) => {
  // Load from localStorage cache immediately — so profile % shows instantly
  const getCached = () => {
    try { const r = localStorage.getItem(CACHE_KEY); return r ? JSON.parse(r) : null; }
    catch { return null; }
  };

  const [profile, setProfileState] = useState(getCached);
  const [loading, setLoading]      = useState(!getCached());

  const setProfile = (p) => {
    setProfileState(p);
    // Cache in localStorage so navigating away/back never shows 0%
    try { if (p) localStorage.setItem(CACHE_KEY, JSON.stringify(p)); }
    catch { /* storage full — ignore */ }
  };

  // Fetch from backend on mount (updates cache with latest data)
  useEffect(() => {
    getStudentProfile()
      .then(p => { setProfile(p); })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  // Update specific fields locally — instant UI update + cache update
  const updateProfileField = (fields) => {
    setProfile(prev => {
      const updated = prev ? { ...prev, ...fields } : fields;
      return updated;
    });
  };

  // Force re-fetch from backend (e.g. after save)
  const refreshProfile = async () => {
    try {
      const p = await getStudentProfile();
      setProfile(p);
    } catch (err) { console.error(err); }
  };

  return (
    <StudentProfileContext.Provider value={{
      profile, setProfile, loading,
      refreshProfile, updateProfileField,
    }}>
      {children}
    </StudentProfileContext.Provider>
  );
};

export const useStudentProfile = () => useContext(StudentProfileContext);
